import React from 'react';

const Hero = () => {
  return (
    <section className="hero">
      <div className="container">
        <div className="hero-content">
          <h1>Accessible Learning for All</h1>
          <h2>Achieve Success with Sky States – Premier Online Programs for Every Learner</h2>
          <p>Explore courses</p>
          <div className="stats">
            <span>29+</span>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
